    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // deposits
        //
        //     {
        //         "transactionId": 1862815,
        //         "timestamp": 1516803982388,
        //         "amountCurrency": "LTC",
        //         "amount": 1,
        //         "fee": 0,
        //         "walletType": "LTC",
        //         "transferType": "DEPOSIT",
        //         "transferStatus": "COMPLETED",
        //         "txid":
        //         "ccb9255dfa874e6c28f1a64179769164025329d65e5201849c2400abd6bce245",
        //         "destination": "LQrtSKA6LnhcwRrEuiborQJnjFF56xqsFn",
        //         "destinationTag": null
        //     }
        //
        // withdrawals
        //
        //     {
        //         "transactionId": 2140966,
        //         "timestamp": 1519314282976,
        //         "amountCurrency": "EUR",
        //         "amount": 8421.7228,
        //         "fee": 16.8772,
        //         "walletType": "BANK_WIRE",
        //         "transferType": "WITHDRAWAL",
        //         "transferStatus": "COMPLETED",
        //         "txid": null,
        //         "destination": null,
        //         "destinationTag": null
        //     }
        //
        // withdraw
        //
        //     {
        //         "id": 2132583,
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(transaction, "timestamp");
        Object currencyId = this.safeString(transaction, "amountCurrency");
        Object code = this.safeCurrencyCode(currencyId, currency);
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", CoinmateCore.this.safeString2(transaction, "transactionId", "id") );
            put( "txid", CoinmateCore.this.safeString(transaction, "txid") );
            put( "type", CoinmateCore.this.safeStringLower(transaction, "transferType") );
            put( "currency", code );
            put( "network", CoinmateCore.this.safeString(transaction, "walletType") );
            put( "amount", CoinmateCore.this.safeNumber(transaction, "amount") );
            put( "status", CoinmateCore.this.parseTransactionStatus(CoinmateCore.this.safeString(transaction, "transferStatus")) );
            put( "timestamp", timestamp );
            put( "datetime", CoinmateCore.this.iso8601(timestamp) );
            put( "address", CoinmateCore.this.safeString(transaction, "destination") );
            put( "addressFrom", null );
            put( "addressTo", null );
            put( "tag", CoinmateCore.this.safeString(transaction, "destinationTag") );
            put( "tagFrom", null );
            put( "tagTo", null );
            put( "updated", null );
            put( "comment", null );
            put( "internal", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "cost", CoinmateCore.this.safeNumber(transaction, "fee") );
                put( "currency", code );
                put( "rate", null );
            }} );
        }};
    }

    /**
     * @method
     * @name coinmate#withdraw
     * @description make a withdrawal
     * @see https://coinmate.docs.apiary.io/#reference/bitcoin-withdrawal-and-deposit/withdraw-bitcoins/post
     * @see https://coinmate.docs.apiary.io/#reference/litecoin-withdrawal-and-deposit/withdraw-litecoins/post
     * @see https://coinmate.docs.apiary.io/#reference/ethereum-withdrawal-and-deposit/withdraw-ethereum/post
     * @see https://coinmate.docs.apiary.io/#reference/ripple-withdrawal-and-deposit/withdraw-ripple/post
     * @see https://coinmate.docs.apiary.io/#reference/cardano-withdrawal-and-deposit/withdraw-cardano/post
     * @see https://coinmate.docs.apiary.io/#reference/solana-withdrawal-and-deposit/withdraw-solana/post
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code, Object amount, Object address, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            var tagparametersVariable = this.handleWithdrawTagAndParams(tag, parameters);
            tag = ((java.util.List<Object>) tagparametersVariable).get(0);
            parameters = ((java.util.List<Object>) tagparametersVariable).get(1);
            this.checkAddress(address);
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object currency = this.currency(code);
            Object withdrawOptions = this.safeValue(this.options, "withdraw", new java.util.HashMap<String, Object>() {{}});
            Object methods = this.safeValue(withdrawOptions, "methods", new java.util.HashMap<String, Object>() {{}});
            Object method = this.safeString(methods, code);
            if (Helpers.isTrue(Helpers.isEqual(method, null)))
            {
                Object allowedCurrencies = Helpers.objectKeys(methods);
                throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " withdraw() only allows withdrawing the following currencies: "), String.join((String)", ", (java.util.List<String>)allowedCurrencies))) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "amount", CoinmateCore.this.currencyToPrecision(code, amount) );
                put( "address", address );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(tag, null)))
            {
                Helpers.addElementToObject(request, "destinationTag", tag);
            }
            Object response = ((java.util.concurrent.CompletableFuture<Object>)Helpers.callDynamically(this, method, new Object[] { this.extend(request, parameters) })).join();
            //
            //     {
            //         "error": false,
            //         "errorMessage": null,
            //         "data": {
            //             "id": "9e0a37fc-4ab4-4b9d-b9e7-c9c8f7c4c8e0"
            //         }
            //     }
            //
            Object data = this.safeValue(response, "data");
            Object transaction = this.parseTransaction(data, currency);
            Object fillResponseFromRequest = this.safeBool(withdrawOptions, "fillResponseFromRequest", true);
            if (Helpers.isTrue(fillResponseFromRequest))
            {
                Helpers.addElementToObject(transaction, "amount", amount);
                Helpers.addElementToObject(transaction, "currency", code);
                Helpers.addElementToObject(transaction, "address", address);
                Helpers.addElementToObject(transaction, "tag", tag);
                Helpers.addElementToObject(transaction, "type", "withdrawal");
                Helpers.addElementToObject(transaction, "status", "pending");
            }
            return transaction;
        });

    }

