    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchMyTrades (private)
        //
        //     {
        //         "transactionId": 2671819,
        //         "createdTimestamp": 1529649127605,
        //         "currencyPair": "LTC_BTC",
        //         "type": "BUY",
        //         "orderType": "LIMIT",
        //         "orderId": 101810227,
        //         "amount": 0.01,
        //         "price": 0.01406,
        //         "fee": 0,
        //         "feeType": "MAKER"
        //     }
        //
        // fetchTrades (public)
        //
        //     {
        //         "timestamp":1561598833416,
        //         "transactionId":"4156303",
        //         "price":10950.41,
        //         "amount":0.004,
        //         "currencyPair":"BTC_EUR",
        //         "tradeType":"BUY"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(trade, "currencyPair");
        market = this.safeMarket(marketId, market, "_");
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "amount");
        Object side = this.safeStringLower2(trade, "type", "tradeType");
        Object type = this.safeStringLower(trade, "orderType");
        Object orderId = this.safeString(trade, "orderId");
        Object id = this.safeString(trade, "transactionId");
        Object timestamp = this.safeInteger2(trade, "timestamp", "createdTimestamp");
        Object fee = null;
        Object feeCostString = this.safeString(trade, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            final Object finalFeeCostString = feeCostString;
            final Object finalMarket = market;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", Helpers.GetValue(finalMarket, "quote") );
            }};
        }
        Object takerOrMaker = this.safeString(trade, "feeType");
        takerOrMaker = ((Helpers.isTrue((Helpers.isEqual(takerOrMaker, "MAKER"))))) ? "maker" : "taker";
        final Object finalMarket_2 = market;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", CoinmateCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket_2, "symbol") );
            put( "type", type );
            put( "side", side );
            put( "order", orderId );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "fee", finalFee );
        }}, market);
    }

